import{_ as t,o as e,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const s=JSON.parse('{"title":"长期主义 Long-term Thinking","description":"如果你不愿意持有一只股票十年，那就不要持有它十分钟","frontmatter":{"title":"长期主义 Long-term Thinking","description":"如果你不愿意持有一只股票十年，那就不要持有它十分钟"},"headers":[],"relativePath":"02_concepts/long-term.md","filePath":"02_concepts/long-term.md"}'),l={name:"02_concepts/long-term.md"};function u(q,o,n,i,c,p){return e(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="长期主义" tabindex="-1">长期主义 <a class="header-anchor" href="#长期主义" aria-label="Permalink to &quot;长期主义&quot;">​</a></h1><blockquote><p>&quot;如果你不愿意持有一只股票十年，那就不要持有它十分钟。&quot; —— 沃伦·巴菲特</p></blockquote><p>长期主义是巴菲特投资哲学的根基，也是区分他与绝大多数投资者的核心思维。在一个充斥着短期噪音、季度财报焦虑和频繁交易冲动的市场中，巴菲特始终坚守&quot;买入并持有&quot;的理念，用时间而非交易来创造财富。</p><hr><h2 id="一、时间是投资者的朋友" tabindex="-1">一、时间是投资者的朋友 <a class="header-anchor" href="#一、时间是投资者的朋友" aria-label="Permalink to &quot;一、时间是投资者的朋友&quot;">​</a></h2><p>巴菲特从不将市场短期波动视为风险，而是将波动本身视为机会。他在多次致股东信中强调：频繁关注股价的涨跌，不仅毫无意义，甚至有害。</p><blockquote><p>&quot;我们合并持有那些优质企业，根本不理会股价的短期波动。总体而言，随着时间的推移，我们将从这些企业的盈利中获益。&quot; —— 巴菲特，1996年致股东信</p></blockquote><p>巴菲特将股票市场比作一个情绪极不稳定的&quot;市场先生&quot;——每天都跑来报价，想卖给你或从你手里买走股份。但理性的投资者不应被这个报价所左右，因为<strong>真正的价值来自企业本身的盈利能力，而非每天变动的股价</strong>。</p><blockquote><p>&quot;对于投资股票的人来说，最大的悲剧之一就是在大跌时割肉卖出。没有人能预测股市的短期走向。&quot; —— 巴菲特，2001年致股东信</p></blockquote><hr><h2 id="二、优质企业的复利奇迹" tabindex="-1">二、优质企业的复利奇迹 <a class="header-anchor" href="#二、优质企业的复利奇迹" aria-label="Permalink to &quot;二、优质企业的复利奇迹&quot;">​</a></h2><p>长期持有的真正力量，来自优质企业利润的持续增长与复利效应的叠加。巴菲特从不追逐短期利润最大化的交易，而是寻找那些&quot;护城河&quot;深厚、能够持续多年创造价值的企业。</p><blockquote><p>&quot;时间是优质企业的朋友，却是平庸企业的敌人。&quot; —— 巴菲特，1992年致股东信</p></blockquote><p>他在1993年致股东信中举过一个经典例子：一家净资产收益率持续保持在20%以上的企业，其内在价值会随时间显著增长，即使市场短期不看好这家公司的股价。<strong>持有时间越长，复利效应越明显</strong>，最终市场会认可其真实价值。</p><blockquote><p>&quot;以合理的价格买进一家优质公司，远比以优质价格买进一家平庸公司要好得多。&quot; —— 巴菲特，1989年致股东信</p></blockquote><hr><h2 id="三、为什么要避免频繁交易" tabindex="-1">三、为什么要避免频繁交易 <a class="header-anchor" href="#三、为什么要避免频繁交易" aria-label="Permalink to &quot;三、为什么要避免频繁交易&quot;">​</a></h2><p>大多数投资者在交易中损耗了大量利润——每次交易都伴随着佣金、税费和机会成本。更致命的是，频繁交易往往让人陷入&quot;追涨杀跌&quot;的恶性循环，在最高点买入、在最低点割肉。</p><blockquote><p>&quot;华尔街是靠 people&#39;s money（别人的钱）来运作的，这与大多数投资者的利益相悖。短期视野驱动了这个行业，但这对投资者来说极其不利。&quot; —— 巴菲特，1996年致股东信</p></blockquote><p>巴菲特在伯克希尔60年的历史中，很少频繁调整持仓。他的绝大多数重大收益，都来自少数几家长期持有的公司——可口可乐、美国运通、富国银行、吉列（后来的宝洁）。</p><blockquote><p>&quot;真正好的投资机会是罕见的。当我们找到它时，我们想要充分参与其中，并长期持有。&quot; —— 巴菲特，1994年致股东信</p></blockquote><hr><h2 id="四、用-十年测试法-做决策" tabindex="-1">四、用&quot;十年测试法&quot;做决策 <a class="header-anchor" href="#四、用-十年测试法-做决策" aria-label="Permalink to &quot;四、用&quot;十年测试法&quot;做决策&quot;">​</a></h2><p>巴菲特有一个简单而有效的决策标准，可以帮助投资者过滤掉大多数噪音：<strong>当你考虑买进一只股票时，想象一下股市将在未来十年关闭，你是否仍然愿意持有它？</strong></p><blockquote><p>&quot;如果十年后你不想持有这只股票，那就不要考虑现在持有它。&quot; —— 巴菲特，1996年致股东信</p></blockquote><p>这个测试的本质，是将投资者的视角从短期价格波动中抽离出来，聚焦于企业本身的长期价值创造能力。如果一个商业模式在十年后仍具竞争力，那么当前的股价波动就变得无关紧要。</p><hr><h2 id="五、耐心-最被低估的投资美德" tabindex="-1">五、耐心：最被低估的投资美德 <a class="header-anchor" href="#五、耐心-最被低估的投资美德" aria-label="Permalink to &quot;五、耐心：最被低估的投资美德&quot;">​</a></h2><p>在巴菲特看来，耐心是投资中最重要的品质，甚至超过智力。他曾在多个场合引用他的导师本杰明·格雷厄姆的话，强调<strong>决定投资成功与否的，往往是你在场外等待的那段时间</strong>。</p><blockquote><p>&quot;投资的关键不在于你的行动有多频繁，而在于你的决策质量，以及你是否能在正确的事情上坚持不动摇。&quot; —— 巴菲特，1996年致股东信</p></blockquote><p>巴菲特本人也以超乎常人的耐心著称。他曾在1987年股灾前、2000年互联网泡沫期间和2008年金融危机中，出人意料地按兵不动，甚至逆势加仓优质资产。这种逆向操作，正是耐心带来的认知优势。</p><blockquote><p>&quot;在别人恐惧时贪婪，在别人贪婪时恐惧。&quot; —— 沃伦·巴菲特</p></blockquote><hr><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><p>长期主义的本质，是对时间的尊重和对复利的信仰。巴菲特的财富帝国，某种意义上就是&quot;耐心&quot;二字的复利成果。对于每一位投资者来说，理解这一点并真正践行它，比任何投资技巧都更有价值。</p><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="./value-investment.html">价值投资</a> — 长期主义的理论基础</li><li><a href="./economic-moat.html">护城河</a> — 什么样的企业值得长期持有</li><li><a href="./margin-of-safety.html">安全边际</a> — 长期持有的风险控制</li><li><a href="./mr-market.html">市场先生</a> — 如何应对短期波动</li><li><a href="./circle-of-competence.html">能力圈</a> — 为什么要只投你懂的</li></ul>',38)])])}const b=t(l,[["render",u]]);export{s as __pageData,b as default};
